```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));

    NetworkPacket packet;

    // Read packet_id using read function
    adaptor.read(&packet.packet_id, sizeof(packet.packet_id));

    // Read username using prefixed adaptor
    adaptor >> hexi::prefixed(packet.username);

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    adaptor.read_container(packet.scores, score_count);

    // Read metadata using null_terminated adaptor
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    size_t padding = buffer.size() - adaptor.total_read();
    if (padding > 0) {
        adaptor.skip(padding);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = id_span[0];

    // Read username using prefixed adaptor
    adaptor >> hexi::prefixed(info.username);

    // Skip scores vector by reading count and skipping data
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Points:

1. **Buffer Adaptor Creation**: Both functions create a `buffer_adaptor` from the input buffer using `const_cast` to handle the const span.

2. **Deserialization Function**:
   - Uses `read()` function for `packet_id`
   - Uses `prefixed` adaptor for username (length-prefixed string)
   - Reads score count then uses `read_container` for the scores vector
   - Uses `null_terminated` adaptor for metadata
   - Calculates and skips padding bytes

3. **Extract Function**:
   - Uses `span()` for zero-copy packet_id access
   - Uses `prefixed` adaptor for username (returns string_view)
   - Reads score count then skips the scores data using `skip()`
   - No metadata or padding handling needed

4. **Proper Error Handling**: The implementation assumes the buffer contains valid data as specified in the requirements.

