#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator for integers with the specified element count
    hexi::block_allocator<int, element_count> allocator;

    std::cout << "Demonstrating block_allocator free list management with " 
              << element_count << " elements\n";

    // First allocation - should come from preallocated slab (uses pop())
    int* ptr1 = allocator.allocate(42);
    std::cout << "Allocated first block (value: " << *ptr1 << "). Free list size decreased.\n";

    // Second allocation - still within preallocated slab
    int* ptr2 = allocator.allocate(100);
    std::cout << "Allocated second block (value: " << *ptr2 << "). Free list size decreased further.\n";

    // Deallocate first block - returns it to free list (uses push())
    allocator.deallocate(ptr1);
    std::cout << "Deallocated first block. Free list size increased.\n";

    // Third allocation - should reuse the deallocated block (uses pop() again)
    int* ptr3 = allocator.allocate(200);
    std::cout << "Allocated third block (value: " << *ptr3 << "). Reused previously deallocated slot.\n";

    // Deallocate all remaining blocks
    allocator.deallocate(ptr2);
    allocator.deallocate(ptr3);

    std::cout << "All blocks deallocated. Free list now contains " 
              << element_count << " blocks.\n";

    // Demonstrate fallback allocation when exceeding preallocated slab
    if constexpr (element_count < 20) {
        std::cout << "\nTesting allocation beyond preallocated slab:\n";

        // Allocate until we exceed the preallocated slab
        int* ptr_array[element_count + 5];
        for (size_t i = 0; i < element_count + 5; ++i) {
            ptr_array[i] = allocator.allocate(static_cast<int>(i));
            std::cout << "Allocated block " << i << ". ";
        }

        // Deallocate some to test fallback
        for (size_t i = 0; i < element_count + 5; i += 2) {
            allocator.deallocate(ptr_array[i]);
            std::cout << "Deallocated block " << i << ". ";
        }

        std::cout << "\nAll tests completed. Block allocator demonstrates proper free list management.\n";
    }
}

// Example usage
int main() {
    demonstrate_block_allocator_behavior<5>(); // Test with smaller element count for clearer output
    return 0;
}
```

This implementation demonstrates the free list management by:

1. Showing how allocations initially use the preallocated slab (using `pop()` internally)
2. Demonstrating that deallocations return blocks to the free list (using `push()` internally)
3. Showing that subsequent allocations reuse previously deallocated blocks
4. Testing the fallback mechanism when exceeding the preallocated slab capacity

The code provides clear commentary explaining each operation's effect on the free list, making it easy to understand the internal push/pop behavior without directly accessing private methods.

