```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer with sufficient capacity to hold all chunks
    std::size_t total_size = 0;
    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    std::vector<uint8_t> buffer;
    buffer.reserve(total_size);

    // Create buffer_write_adaptor
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    // Iterate through each chunk and write using the adaptor
    for (const auto& chunk : chunks) {
        // Check available space before each write
        if (adaptor.free() < chunk.size()) {
            // Handle error case - buffer doesn't have enough space
            return 0;
        }

        adaptor.write(chunk.data(), chunk.size());
    }

    // Return the total size written
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> result;

    // Create buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        std::size_t current_chunk_size = std::min(chunk_size, adaptor.size());
        std::vector<uint8_t> chunk(current_chunk_size);

        // Read chunk of data
        adaptor.read(chunk.data(), current_chunk_size);

        // Append to result
        result.insert(result.end(), chunk.begin(), chunk.end());
    }

    return result;
}
